function solve(nums) {
    const n = nums.length;
    let maxVal = 0;

    // Try all possible ways to assign elements to A, B, C
    for (let mask = 0; mask < (1 << n); mask++) {
        const A = [];
        const B = [];
        const C = [];
        for (let i = 0; i < n; i++) {
            if ((mask >> i) & 1) {
                A.push(nums[i]);
            } else {
                B.push(nums[i]);
            }
        }
        // Calculate XOR for A and C
        let xorA = 0;
        for (const num of A) {
            xorA ^= num;
        }
        let xorC = 0;
        for (const num of C) {
            xorC ^= num;
        }
        // Calculate AND for B
        let andB = 0;
        for (const num of B) {
            andB &= num;
        }
        // Update maxVal
        const currentSum = xorA + andB + xorC;
        if (currentSum > maxVal) {
            maxVal = currentSum;
        }
    }

    return maxVal;
}
